import{_ as t,o as e,c as a,a2 as u}from"./chunks/framework.Crpw6aS5.js";const i=JSON.parse('{"title":"声誉","description":"","frontmatter":{},"headers":[],"relativePath":"05_quotes/by-theme/声誉.md","filePath":"05_quotes/by-theme/声誉.md"}'),q={name:"05_quotes/by-theme/声誉.md"};function l(c,o,r,p,n,h){return e(),a("div",null,[...o[0]||(o[0]=[u('<h1 id="声誉" tabindex="-1">声誉 <a class="header-anchor" href="#声誉" aria-label="Permalink to &quot;声誉&quot;">​</a></h1><blockquote><p>&quot;声誉是CEO最宝贵的资产。建立需要二十年，毁掉只需要五分钟。&quot;——巴菲特</p></blockquote><p>声誉经济是巴菲特商业哲学中经常被忽视却贯穿始终的暗线。在他的框架里，声誉不只是美德，更是理性的商业策略。</p><hr><h2 id="核心金句" tabindex="-1">核心金句 <a class="header-anchor" href="#核心金句" aria-label="Permalink to &quot;核心金句&quot;">​</a></h2><blockquote><p>&quot;声誉是CEO最宝贵的资产。建立它需要二十年。毁掉它只需要五分钟。你永远要记住这一点。&quot;</p></blockquote><blockquote><p>&quot;我们宁愿损失金钱，也不愿损失声誉。在伯克希尔，声誉比任何合同都更有约束力。&quot;</p></blockquote><blockquote><p>&quot;当你赢得一个好名声之后，它会为你带来比你付出更多的回报。我们坚持与人为善，因为这是好的商业策略。&quot;</p></blockquote><blockquote><p>&quot;在商界，我见过太多人为了短期利益牺牲长期声誉。最终他们都会后悔。&quot;</p></blockquote><blockquote><p>&quot;如果一个CEO告诉你他的声誉不重要，那他要么是在自欺欺人，要么是在欺骗你。&quot;</p></blockquote><blockquote><p>&quot;我们在选择子公司经理时，品格和才能一样重要。一个有能力但没有品格的人，最终会毁掉他接触的一切。&quot;</p></blockquote><blockquote><p>&quot;查理和我对子公司的管理层有一个简单的期望：像你们自己100%拥有这家公司那样去经营。这意味着像保护自己的声誉一样保护伯克希尔的声誉。&quot;</p></blockquote><blockquote><p>&quot;那些试图通过欺骗客户、供应商或员工来获利的公司，短期可能有账面盈利，长期必然毁灭。我们见过太多这样的案例。&quot;</p></blockquote><hr><h2 id="伯克希尔的声誉实践" tabindex="-1">伯克希尔的声誉实践 <a class="header-anchor" href="#伯克希尔的声誉实践" aria-label="Permalink to &quot;伯克希尔的声誉实践&quot;">​</a></h2><blockquote><p>&quot;B夫人的核心价值观就是&#39;低价卖，说实话&#39;。这五个字成就了内布拉斯加家具城在全美的领先地位。&quot;</p></blockquote><blockquote><p>&quot;我们从不试图在合同条款上占供应商便宜。如果我们的供应商在与我们合作后没有赚到合理的利润，这是我们的失败，不是他们的失败。&quot;</p></blockquote><blockquote><p>&quot;伯克希尔的每一个子公司，都被授权以伯克希尔的名义进行商业活动。这意味着我们必须对他们的行为负全部责任。因此，我们只选择那些有品格的人来运营我们的企业。&quot;</p></blockquote><hr><h2 id="出处年份" tabindex="-1">出处年份 <a class="header-anchor" href="#出处年份" aria-label="Permalink to &quot;出处年份&quot;">​</a></h2><p>1983年 · 1993年 · 2005年 · 2014年 · 2020年</p><hr><h2 id="深入阅读" tabindex="-1">深入阅读 <a class="header-anchor" href="#深入阅读" aria-label="Permalink to &quot;深入阅读&quot;">​</a></h2><p><a href="/02_concepts/management.html">管理层</a> · <a href="/02_concepts/corporate-governance.html">董事会治理</a> · <a href="/02_concepts/underwriting-discipline.html">承保纪律</a></p>',24)])])}const s=t(q,[["render",l]]);export{i as __pageData,s as default};
